            val firstChildNode = node.firstChildNode ?: return
            if (firstChildNode.elementType == BLOCK) {
                return
            }

            if (node.elementType == ELSE && firstChildNode.elementType == IF) {
                // Allow else-if regardless of whether the previous branch spans multiple lines
                return
            }

            if (!node.treePrev.textContains('\n')) {
                if (!node.treeParent.textContains('\n')) {
                    // Allow single line if statements as long as they are really simple (e.g. do not contain newlines)
