import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class MultiLineIfElseRuleElseIfRegressionTest {
    private val multiLineIfElseRuleAssertThat = assertThatRule { MultiLineIfElseRule() }

    @Test
    fun `Given a multiline else-if chain with an elvis operator then do not force braces`() {
        val code =
            """
            fun foo(showFilter: Boolean, activeTabIndex: Int?): Int {
                val value =
                    if (showFilter) {
                        1
                    } else if ((activeTabIndex ?: 0) == 0) {
                        2
                    } else {
                        null
                    } ?: 0
