        when (val psi = psi) {
            is KtIfExpression -> true
            is KtBinaryExpression -> psi.left?.node?.startsWithIfExpression() ?: false
            is KtDotQualifiedExpression -> psi.receiverExpression.node.startsWithIfExpression()
            is KtSafeQualifiedExpression -> psi.receiverExpression.node.startsWithIfExpression()
            is KtParenthesizedExpression -> psi.expression?.node?.startsWithIfExpression() ?: false
            is KtPostfixExpression -> psi.baseExpression?.node?.startsWithIfExpression() ?: false
            is KtPrefixExpression -> psi.baseExpression?.node?.startsWithIfExpression() ?: false
